import{_ as e,a as r,b as d,c as o}from"./chunks/fizz.C1J5EiKo.js";import{_ as a,o as n,c as s,a2 as i}from"./chunks/framework.CY0RMtsF.js";const c="/mug-typography-docs/image/inspector_animation_settings.webp",l="/mug-typography-docs/image/inspector_animation_hand_drawn.webp",g="/mug-typography-docs/image/jiggly.webp",h="/mug-typography-docs/image/hand_drawn_pattern_count_1.webp",y=JSON.parse('{"title":"アニメーション設定 (Animation Settings)","description":"","frontmatter":{"title":"アニメーション設定 (Animation Settings)"},"headers":[],"relativePath":"reference/reference-animation-settings.md","filePath":"reference/reference-animation-settings.md"}'),p={name:"reference/reference-animation-settings.md"};function b(m,t,f,u,_,S){return n(),s("div",null,[...t[0]||(t[0]=[i('<h1 id="page-animation-settings" tabindex="-1">Page: Animation Settings <a class="header-anchor" href="#page-animation-settings" aria-label="Permalink to &quot;Page: Animation Settings&quot;">​</a></h1><p>キーフレームの設定・削除・最適化・ランダマイズと、手描き風エフェクトおよびパス変形エフェクトを設定するページです。</p><div class="caution custom-block github-alert"><p class="custom-block-title">CAUTION</p><p><strong>Edit ページで分割（カット）したクリップへのキーフレーム設定について</strong><br> Edit ページで分割したクリップに対して、本プラグインからキーフレームを設定（オートキーフレーム、ビューア上の操作、<code>Alt+K</code> による打刻など）すると、キーフレームが正しい位置に設定されません。これは DaVinci Resolve 側の仕様による問題で、プラグイン側では対応できません。このため、本プラグインを適用するクリップは<strong>分割しない運用を推奨します</strong>（詳細は付録の「<a href="#limitations-ja">制限事項</a>」を参照）。</p></div><p><img src="'+c+'" alt="Animation"></p><h2 id="オートキーフレーム" tabindex="-1">オートキーフレーム <a class="header-anchor" href="#オートキーフレーム" aria-label="Permalink to &quot;オートキーフレーム&quot;">​</a></h2><table tabindex="0"><thead><tr><th>パラメーター</th><th>説明</th></tr></thead><tbody><tr><td><strong>Auto Key Frame</strong></td><td>ON にすると、パラメーターを変更するたびに自動的にキーフレームが設定されます。</td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>移動・回転などの操作のたびにキーフレームが記録されるため、意図せず大量のキーフレームが作成されたり、意図しないアニメーションが設定されることがあります。アニメーションを付けない場合は OFF のまま使用してください。</p></div><h2 id="キーフレームの手動設定" tabindex="-1">キーフレームの手動設定 <a class="header-anchor" href="#キーフレームの手動設定" aria-label="Permalink to &quot;キーフレームの手動設定&quot;">​</a></h2><table tabindex="0"><thead><tr><th>パラメーター</th><th>説明</th></tr></thead><tbody><tr><td><strong>Set Keyframes for Selected (Alt+K)</strong></td><td>現在選択中の文字・パーツに対して、現在フレームの値をキーフレームとして記録します。値は変更しません。（ショートカットキー <code>Alt+K</code> / macOS: <code>Option+K</code> でも実行可能）</td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>記録されるパラメーターは選択モードによって異なります。</p><ul><li><strong>Global</strong>: Pos / Pivot / Rotation / Stretch / Scale / Font Color / Tracking / Stroke Width / Stroke Color / Draw Global Shadow / Shadow Distance / Shadow Angle / Shadow Color</li><li><strong>Character</strong>: Pos / Pivot / Scale / Stretch / Rotation / Margin After / Use Indiv Color / Color / Use Indiv Stroke / Stroke Width / Stroke Gap / Stroke Color</li><li><strong>Part</strong>: Pos / Pivot / Scale / Rotation / Stretch / Use Indiv Color / Color</li></ul></div><h2 id="キーフレームの最適化-optimize-keyframes" tabindex="-1">キーフレームの最適化（Optimize Keyframes） <a class="header-anchor" href="#キーフレームの最適化-optimize-keyframes" aria-label="Permalink to &quot;キーフレームの最適化（Optimize Keyframes）&quot;">​</a></h2><p>すべてのアニメーションパラメータから、値が変化しない不要なキーフレームを自動で検出して一括削除し、整理する機能です。</p><table tabindex="0"><thead><tr><th>パラメーター</th><th>説明</th></tr></thead><tbody><tr><td><strong>Optimize All Parameters</strong></td><td>クリックすると確認ダイアログが表示され、全パラメータをスキャンして冗長な（すべてのキーで同じ値を持つ）キーフレームを一括削除し、パラメータを単一値（キーフレームなし）に整理します。</td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>移動や変形時の「オートキーフレーム」などで意図せず大量に記録されてしまったキーフレームを整理するのに便利です。不要なキーフレームを削減することで、動作パフォーマンスの向上が期待できます。 完了後に削除されたキーフレーム数がダイアログで通知されます。</p></div><h2 id="キーフレームの削除-delete-keys" tabindex="-1">キーフレームの削除（Delete Keys） <a class="header-anchor" href="#キーフレームの削除-delete-keys" aria-label="Permalink to &quot;キーフレームの削除（Delete Keys）&quot;">​</a></h2><p>指定した時間範囲内のキーフレームをまとめて削除できます。</p><table tabindex="0"><thead><tr><th>パラメーター</th><th>説明</th></tr></thead><tbody><tr><td><strong>Time Mode</strong></td><td>範囲指定を Relative（相対フレーム）か Absolute（絶対フレーム）で行うか選びます。</td></tr><tr><td><strong>Start (frame)</strong></td><td>削除範囲の開始フレーム。</td></tr><tr><td><strong>Start (sec)</strong></td><td>開始位置の秒数表示（参照用）。</td></tr><tr><td><strong>End (frame)</strong></td><td>削除範囲の終了フレーム。</td></tr><tr><td><strong>End (sec)</strong></td><td>終了位置の秒数表示（参照用）。</td></tr><tr><td><strong>Delete Keys in Range (Selected)</strong></td><td>選択項目の指定範囲内キーフレームをすべて削除します。</td></tr></tbody></table><h2 id="パス変形エフェクト-path-deformation-effects" tabindex="-1">パス変形エフェクト（Path Deformation Effects） <a class="header-anchor" href="#パス変形エフェクト-path-deformation-effects" aria-label="Permalink to &quot;パス変形エフェクト（Path Deformation Effects）&quot;">​</a></h2><p>手描き風エフェクトに加えて、文字のアウトライン（輪郭）を規則的に歪ませる、4つの変形エフェクトが用意されています。 それぞれを ON（Enabled）にすることで、パラメータに応じた独自の変形・アニメーション効果を適用できます。</p><h3 id="_1-パルスエフェクト-pulse-effect" tabindex="-1">1. パルスエフェクト（Pulse Effect） <a class="header-anchor" href="#_1-パルスエフェクト-pulse-effect" aria-label="Permalink to &quot;1. パルスエフェクト（Pulse Effect）&quot;">​</a></h3><p>文字の輪郭を外側・内側へ伸縮させ、呼吸しているかのように太くなったり細くなったりする効果です。</p><p><img src="'+e+'" alt="パルスエフェクトの表示例"></p><h3 id="_2-台形変形エフェクト-trapezoid-effect" tabindex="-1">2. 台形変形エフェクト（Trapezoid Effect） <a class="header-anchor" href="#_2-台形変形エフェクト-trapezoid-effect" aria-label="Permalink to &quot;2. 台形変形エフェクト（Trapezoid Effect）&quot;">​</a></h3><p>文字を任意のアングル（角度）の軸に沿って台形に歪ませる（遠近感を出す）効果です。 軸を傾けることで、すぼまる方向を自由に変更でき、時間経過で台形と逆台形を往復するような動きを作成できます。</p><p><img src="'+r+'" alt="台形変形エフェクトの表示例"></p><h3 id="_3-球面化エフェクト-sphere-effect" tabindex="-1">3. 球面化エフェクト（Sphere Effect） <a class="header-anchor" href="#_3-球面化エフェクト-sphere-effect" aria-label="Permalink to &quot;3. 球面化エフェクト（Sphere Effect）&quot;">​</a></h3><p>文字のアウトラインを球面上に投影し、バルーンのように中央をプクッと膨らませたり、逆にピンチ（すぼめる）したりする効果です。</p><p><img src="'+d+'" alt="球面化エフェクトの表示例"></p><h3 id="_4-樽型歪みエフェクト-barrel-effect" tabindex="-1">4. 樽型歪みエフェクト（Barrel Effect） <a class="header-anchor" href="#_4-樽型歪みエフェクト-barrel-effect" aria-label="Permalink to &quot;4. 樽型歪みエフェクト（Barrel Effect）&quot;">​</a></h3><p>文字の中心から外側に向けてスケールを徐々に変化させ、樽のように中央が膨らんだ歪み（または糸巻き型の歪み）を与える効果です。</p><p><img src="'+o+'" alt="樽型歪みエフェクトの表示例"></p><h3 id="変形エフェクト共通パラメータ" tabindex="-1">変形エフェクト共通パラメータ <a class="header-anchor" href="#変形エフェクト共通パラメータ" aria-label="Permalink to &quot;変形エフェクト共通パラメータ&quot;">​</a></h3><table tabindex="0"><thead><tr><th>パラメーター</th><th>説明</th><th>デフォルト</th></tr></thead><tbody><tr><td><strong>Enabled</strong></td><td>ON にするとエフェクトを有効にします。アニメーション可能。</td><td>OFF</td></tr><tr><td><strong>Amplitude</strong></td><td>変形の強さ（振幅）を指定します。各エフェクトにおける具体的な意味は下記の通りです。<br>・<strong>Pulse</strong>: 輪郭を外側・内側へ伸縮させる量。<br>・<strong>Trapezoid</strong>: すぼまり（テーパー）の強さ。1.0で片端が完全に潰れます。<br>・<strong>Sphere</strong>: 球面状の膨らみの強さ。1.0で完全な球面になります。<br>・<strong>Barrel</strong>: 中央の膨らみ（樽型）の強さ。1.0で外縁部が倍の大きさまで広がります。<br>✨ ※ <strong>Sphere / Barrel</strong> はスライダーの表示範囲は <code>0.0〜1.0</code> ですが、数値を直接入力することで <code>-10.0〜10.0</code> まで指定でき、より強い歪みや（負値による）反転した歪みを表現できます。</td><td>(エフェクトによる)</td></tr><tr><td><strong>Range Min</strong><br>※Trapezoidを除く</td><td>変形の振れ幅の下限値を指定します。-1.0〜1.0。<br>0.0に設定することで、拡大方向のみ（または縮小方向のみ）に変形を制限できます。</td><td><code>-1.0</code></td></tr><tr><td><strong>Range Max</strong><br>※Trapezoidを除く</td><td>変形の振れ幅の上限値を指定します。-1.0〜1.0。<br>0.0に設定することで、縮小方向のみ（または拡大方向のみ）に変形を制限できます。</td><td><code>1.0</code></td></tr><tr><td><strong>Speed (Hz)</strong></td><td>アニメーションの速度をヘルツ（1秒あたりの往復回数）で指定します。</td><td><code>2.0</code></td></tr><tr><td><strong>Angle</strong><br>※Trapezoidのみ</td><td>台形変形の軸の角度を指定します。角度によってすぼまる方向が変わります。</td><td><code>0°</code></td></tr><tr><td><strong>Step</strong></td><td>位相（角度）を段階的に変化させるステップサイズを指定します（度数法）。<br>0.0で滑らかなアニメーション、360.0に設定するとアニメーションが停止して静的になります。</td><td><code>0.0</code></td></tr><tr><td><strong>Phase</strong></td><td>アニメーションの全体的な開始位相オフセットを度数法で指定します。</td><td><code>0°</code></td></tr><tr><td><strong>Char Phase</strong></td><td>文字インデックスごとに加算される位相オフセットを指定します（度数法）。<br>値を設定することで、左から右へ（または右から左へ）変形が波のように伝わっていくアニメーションになります。</td><td><code>0°</code></td></tr><tr><td><strong>Char Delay</strong></td><td>文字インデックスごとに加算される開始遅延時間（秒）を指定します。<br>文字ごとにタイミングをずらして変形を開始させたいときに使用します。</td><td><code>0.0</code></td></tr><tr><td><strong>Targets</strong></td><td>エフェクトを適用する対象の文字・パーツを指定します。記述方法は「<a href="#targets-format-ja">Targets（対象指定）の記述フォーマット</a>」を参照してください（文字単位 <code>c1</code> / パーツ単位 <code>p5</code> / 範囲 <code>c1-c3</code> / 否定 <code>!c2</code> などが使用できます）。<br><strong>空欄の場合はすべてのパーツに適用されます。</strong> 特定の文字だけを歪ませたり、否定指定（例: <code>!c1</code>）で濁点や特定の文字だけを変形対象から除外したりする際に便利です。</td><td>(空)</td></tr></tbody></table><hr><h2 id="手描き風エフェクト-hand-drawn-effect" tabindex="-1">手描き風エフェクト（Hand Drawn Effect） <a class="header-anchor" href="#手描き風エフェクト-hand-drawn-effect" aria-label="Permalink to &quot;手描き風エフェクト（Hand Drawn Effect）&quot;">​</a></h2><p><img src="'+l+'" alt="Hand Drawn Effect"></p><p><img src="'+g+'" alt="Hand Drawn Effect"></p><p>テキストに有機的な手描き風のアニメーションを付加する機能です。文字の輪郭線（パス）をランダムに波打たせる「ウォブル」と、文字の位置・回転・スケールをフレームごとに微妙にずらす「ジッター」の2種類の効果を組み合わせて、手書きで書いたようなゆらぎを表現します。</p><table tabindex="0"><thead><tr><th>パラメーター</th><th>説明</th><th>デフォルト</th></tr></thead><tbody><tr><td><strong>Enabled</strong></td><td>ON にするとエフェクトを有効にします。アニメーション可能。</td><td>OFF</td></tr><tr><td><strong>Pattern Count</strong></td><td>ループするパターンのコマ数。パラパラ漫画のコマ数のイメージで、この数のパターンを順に切り替えながら繰り返します。</td><td>3</td></tr><tr><td><strong>Wobble Amplitude</strong></td><td>輪郭線の波打ち（ウォブル）の強さ。0 でウォブルなし。アニメーション可能。</td><td>3.0</td></tr><tr><td><strong>Fine Wobble</strong></td><td>手書きの微細な手の震え（局所的なブレ）の強さ。0 で震えなし。アニメーション可能。</td><td>0.15</td></tr><tr><td><strong>Jitter Amplitude</strong></td><td>文字の位置ずれ（ジッター）の強さ。0 でジッターなし。アニメーション可能。</td><td>2.0</td></tr><tr><td><strong>Frame Rate</strong></td><td>エフェクトのパターンが切り替わる速度（回/秒）。低い値ほど変化がゆっくりになります。アニメーション可能。</td><td>6.0</td></tr><tr><td><strong>Seed</strong></td><td>ウォブル・ジッターのランダムパターンを決定するシード値。値を変えると別のパターンになります。</td><td>0</td></tr><tr><td><strong>Targets</strong></td><td>エフェクトを適用する対象の文字・パーツを指定します。記述方法は「<a href="#targets-format-ja">Targets（対象指定）の記述フォーマット</a>」を参照してください（文字単位 <code>c1</code> / パーツ単位 <code>p5</code> / 範囲 <code>c1-c3</code> / 否定 <code>!c2</code> などが使用できます）。<strong>空欄の場合はすべてのパーツに適用されます。</strong></td><td>(空)</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p><strong>使いこなしのヒント</strong></p><ul><li>まず <code>Enabled</code> を ON にすれば、デフォルト値のまま自然な手描き風のゆらぎが付きます。</li><li>揺れが強すぎると感じたら、<code>Wobble Amplitude</code>（輪郭の波打ち）と <code>Jitter Amplitude</code>（位置ずれ）を下げてください。</li><li>揺れの速さは <code>Frame Rate</code> で調整します。低くするとゆっくりした動きになります。</li><li><code>Pattern Count</code> を <code>1</code> にすると、ゆらぎが静止した（動かない）手描き風の見た目になります。動かさず質感だけ欲しいときに便利です。</li></ul><p><img src="'+h+'" alt="Pattern Count 1"><em>ギザギザ・トゲトゲにする例</em></p></div><h2 id="ランダマイズ-randomize" tabindex="-1">ランダマイズ（Randomize） <a class="header-anchor" href="#ランダマイズ-randomize" aria-label="Permalink to &quot;ランダマイズ（Randomize）&quot;">​</a></h2><p>選択した文字・パーツに対して、指定した範囲内のランダムな値を一括で適用し、同時にキーフレームとして記録します。アニメーションの初期状態を素早く作るのに便利です。</p><table tabindex="0"><thead><tr><th>パラメーター</th><th>説明</th><th>デフォルト範囲</th></tr></thead><tbody><tr><td><strong>Pos X</strong></td><td>X 位置をランダム化（ON/OFF + Min / Max）</td><td>0.4 ～ 0.6</td></tr><tr><td><strong>Pos Y</strong></td><td>Y 位置をランダム化（ON/OFF + Min / Max）</td><td>0.4 ～ 0.6</td></tr><tr><td><strong>Scale</strong></td><td>スケールをランダム化（ON/OFF + Min / Max）</td><td>0.7 ～ 1.3</td></tr><tr><td><strong>Rotation</strong></td><td>回転をランダム化（ON/OFF + Min / Max）</td><td>-30° ～ +30°</td></tr><tr><td><strong>Stretch X</strong></td><td>X 方向ストレッチをランダム化（ON/OFF + Min / Max）</td><td>0.8 ～ 1.2</td></tr><tr><td><strong>Stretch Y</strong></td><td>Y 方向ストレッチをランダム化（ON/OFF + Min / Max）</td><td>0.8 ～ 1.2</td></tr><tr><td><strong>Randomize Selected (Set Key)</strong></td><td>チェック済み項目を選択文字・パーツに適用し、キーフレームとして記録します。</td><td></td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>Min / Max に指定する値は<strong>絶対値</strong>です。現在の値へのオフセットではなく、指定した範囲内の値がそのままパラメーターにセットされます。</p></div><p><strong>ランダマイズの手順：</strong></p><ol><li>ランダム化したい項目の ON/OFF を有効にする</li><li>Min / Max 値を設定する</li><li>プレビュー画面でランダム化したい文字・パーツを選択する</li><li><strong>Randomize Selected (Set Key)</strong> ボタンを押す</li></ol><p><a id="page-copy-paste"></a></p>',47)])])}const O=a(p,[["render",b]]);export{y as __pageData,O as default};
